-- Query: 000AuditReport_OLD2
SELECT [000AuditSessionSelect].CustomerID, [000AuditSessionSelect].LastName, [000AuditSessionSelect].FirstName, [000AuditSessionSelect].Gender, [000AuditSessionSelect].Address, [000AuditSessionSelect].City, [000AuditSessionSelect].State, [000AuditSessionSelect].ZipCode, [000AuditSessionSelect].Phone, [000AuditSessionSelect].StudentID, [000AuditSessionSelect].SchoolID, [000AuditSessionSelect].WebPassword, [000AuditSessionSelect].SessionNumber, [000AuditSessionSelect].SessionID, [000AuditSessionSelect].SessionItemID, [000AuditSessionSelect].Description, [000AuditSessionSelect].DateTime, [000AuditSessionSelect].TotalDue, [000AuditSessionSelect].Payments, [000AuditSessionSelect].SalesTaxRate, [000AuditOrdersAmount].OrderID, [000AuditOrdersAmount].OrderNumber, [000AuditOrdersAmount].OrderDate, IIf(IsNull([OrderTotal]),0,[OrderTotal]) AS OrderBalDue, IIf(IsNull([000AuditOrdersAmount].[TotalOrder]),0,[000AuditOrdersAmount].[TotalOrder]) AS TotalOrder, IIf(IsNull([000AuditOrdersTotalPayments].[TotalOrderPayments]),0,[000AuditOrdersTotalPayments].[TotalOrderPayments]) AS TotalOrderPayments, Schools.School, [000AuditOrdersPayments].Date AS DatePaid, IIf(IsNull([Method]),"",IIf([Method]=1,"Check",IIf([Method]=2,"Credit Card","Cash"))) AS PaymentMethod, [000AuditOrdersPayments].Amount
FROM (((000AuditSessionSelect LEFT JOIN 000AuditOrdersAmount ON [000AuditSessionSelect].CustomerID = [000AuditOrdersAmount].CustomerID) LEFT JOIN Schools ON [000AuditSessionSelect].SchoolID = Schools.SchoolID) LEFT JOIN 000AuditOrdersTotalPayments ON ([000AuditOrdersAmount].OrderID = [000AuditOrdersTotalPayments].OrderID) AND ([000AuditOrdersAmount].CustomerID = [000AuditOrdersTotalPayments].CustomerID)) LEFT JOIN 000AuditOrdersPayments ON ([000AuditOrdersTotalPayments].OrderID = [000AuditOrdersPayments].OrderID) AND ([000AuditOrdersTotalPayments].CustomerID = [000AuditOrdersPayments].CustomerID);

